def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_capacity in enumerate(bins):
        if bin_capacity <= 0:
            priorities[i] = float('inf')
            continue
        utilization = item / bin_capacity
        if utilization > 1:
            priorities[i] = float('inf')
            continue
        score = 0
        multiplier = 1
        for j in range(1, 8):
            factor = j * utilization
            if factor < 0.2:
                score += np.exp(-factor) * np.sqrt(j)
            elif 0.2 <= factor < 0.4:
                score += np.tan(factor * np.pi / 3) + np.log1p(j)
            elif 0.4 <= factor < 0.6:
                score += np.sinh(factor) / (j + 1)
            elif 0.6 <= factor < 0.9:
                score += np.cos(factor * np.pi / 2) * j
            else:
                score += (factor ** 2) / (j ** 1.5)
            if j % 3 == 0:
                score *= (1 + 0.05 / (j + factor))
            if j % 4 == 1:
                multiplier *= (1 - 0.01 * factor)
        if item < 0.3:
            if bin_capacity > item * 5:
                score *= 1.3 + 0.1 * np.sin(score)
            else:
                score *= 0.85 - 0.05 * np.cos(score)
            for m in range(1, 5):
                score += np.arctan(m * utilization) / (m + 1)
        elif 0.3 <= item <= 1.0:
            if bin_capacity < item * 2.5:
                score *= 1.5
            elif bin_capacity > item * 7:
                score *= 0.6
            else:
                for m in range(1, 6):
                    val = np.tanh(m * utilization) * np.sin(0.2 * m * score)
                    score += val
                    if val > 0.1:
                        score += val ** 2 / (m + 1)
        else:
            max_iters = max(1, int(bin_capacity // item))
            for k in range(1, max_iters + 1):
                increment = np.log(k + utilization + 2)
                if increment > 0.7:
                    score += increment * 0.6 * np.cos(k + utilization)
                else:
                    score += (increment ** 2) * np.sin(k / (utilization + 1))
                if k % 2 == 0:
                    score *= (1 + 0.02 / (k + 1))
            if bin_capacity < item * 4:
                score *= 1.4 - 0.1 * np.tanh(score)
            elif bin_capacity > item * 9:
                score *= 0.5 + 0.05 * np.cos(score)
        if score < 0:
            score = abs(score) + 2
        score *= multiplier
        if np.isnan(score) or np.isinf(score):
            score = float('inf')
        priorities[i] = score
    return priorities
